var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"후우…. 후…. 공기가 점점 차가워지네요.","JPN":"ふう……ふ……空気がだんだん冷たくなってきましたね。","ENG":"*Huff...* *Huff...* The air's getting colder.","TWN":"呼呼……呼……好像變涼咧？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"침식파 밀도도 조금씩 증가하고 있어요. 이게 노르드나빅의 겨울이군요.","JPN":"侵食波密度も少しずつ増加しています。これがノルドナビックの冬なんですね。","ENG":"The Corruption ray density is increasing, too. So this is Nordnavik's winter...","TWN":"侵蝕波的密度也一點一點地增加中，這就是諾爾德萊比的冬天嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그렇습니다. 우리 나라에서는 일반적인 기상 변화로 눈이 내리는 일이 사라졌으니까요.","JPN":"そのとおりです。我が国では一般的な気象変動で雪が降ることがなくなりましたから。","ENG":"That's correct. Snow doesn't naturally occur through weather changes in our country anymore.","TWN":"沒錯，在我們國家已經不會因為正常的氣候變化而下雪。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"옛 아발론의 낙원문이 침식의 겨울을 삼킨 뒤로부터 말이죠.","JPN":"昔、アバロンの楽園の門が侵食の冬を飲み込んでからは。","ENG":"Ever since Avalon's Gate that stood in Old Avalon devoured Corrupted Winter, that is.","TWN":"自從阿瓦隆的樂園門吞噬掉侵蝕的冬天後便是如此。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"와아, 침식 현상의 전조를 눈이 내리는 걸로 확인할 수 있다니. 정말 흥미롭네요.","JPN":"わあ、侵食現象の前兆を雪が降ることで確認できるなんて。とても興味深いです。","ENG":"Wow... It's so interesting being able to confirm the Counterside Effect with just snow.","TWN":"哇，竟然可以藉由下雪來確認侵蝕現象的預兆，真有意思。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"아… 아앗! 흥미롭다고 해서 죄송해요! 여러분에겐 정말 비극적인 일이었을 텐데…","JPN":"あ……ああっ！　興味深いなんて言ってすみません！　みなさんにとっては悲劇的なことだったでしょうに……","ENG":"O-oops! I'm sorry for calling in interesting! I'm sure it was a tragedy for all of you...","TWN":"哎…哎呀！對不起，我竟然說真有意思！這對大家來說應該是個悲劇吧……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아뇨. 한나 씨의 기업이 저희와 협력하는 것도 이런 특이현상을 조사하기 위해서니까요.","JPN":"いいえ。ハンナさんの企業が協力してくださるのも、こういう特異現象を調査するためですから。","ENG":"No need. One reason why your company and we are partnering is to examine this anomaly.","TWN":"沒事，你們的企業之所以會和我們合作，就是要調查這種特殊現象。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"후후, 사실 이런 현상도 현상이지만, 전 성유물이 어떤 물건일지가 제일 궁금해요.","JPN":"ふふ、実はこんな現象もそうですけど、私は聖遺物がどんなものなのかが一番気になるんです。","ENG":"Hu hu. Although this in itself is interesting, I'm curious to see what the Holy Relic looks like.","TWN":"呵呵，話是沒錯，但我最好奇的，其實是聖遺物到底是什麼。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"제가 여기 자원한 것도 20년 전에 침식을 막아 주는 아티팩트가 있었단 얘기 때문이었어요.","JPN":"ここを志願したのも、20年前当時に侵食を止めていたアーティファクトがあるって話があったからなんですよ。","ENG":"I volunteered to come after hearing about an artifact that shielded this place from Corruption 20 years ago.","TWN":"我會自願來這裡，也是因爲聽說20年前抵擋侵蝕的人造神器就在這裡。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"게다가 보안 때문에 직계 왕족들도 대부분 그 정체를 몰랐다잖아요?","JPN":"それに保安のせいで直系の王族もほとんどその正体を知らなかったらしいじゃないですか。","ENG":"Furthermore, even most of the Royal family didn't know what it looked like for security reasons, right?","TWN":"而且我聽說基於安全的理由，就連大部分的皇族也不知道呢。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"저희 같은 과학도 입장에서는 관심을 안 가질 수가 없거든요.","JPN":"私たち研究員の立場からすれば、どうしても興味が湧いてしまうんです。","ENG":"This is something that any scientist in my field would be interested in.","TWN":"我們這樣的科學家怎麼可能不感興趣。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"조만간 그 정체를 확인할 수 있을 겁니다. 탐지기의 신호도 이제 그리 멀지 않으니까요.","JPN":"近いうちにその正体を確認できるはずです。探知機の信号もそれほど遠くはありませんから。","ENG":"We'll know soon enough. The signal says it's not far from here.","TWN":"很快就可以一窺究竟，探測器的訊號顯示距離沒有很遠。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"좋아요. 드디어 지난 3개월 동안의 노력을 보상 받을 수 있겠네요.","JPN":"はい。やっと3カ月間の努力が報われそうですね。","ENG":"Okay. I guess this is where 3 months worth of work finally pay off!","TWN":"太好啦，過去三個月的努力終於要有回報啦！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"아, 잠시만요. 제가 먼저 올라갈게요.","JPN":"あ、待ってください。私が先に上ります。","ENG":"Oh, hold on. I'll go up first.","TWN":"先等一下，我先上去。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"…읏차아!","JPN":"……よいしょっと！","ENG":"Hup...!","TWN":"…呃啊啊！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"여기요. 제 손을 잡고 올라오세요.","JPN":"さあ。私の手を取って上ってきてください。","ENG":"Here. Grab my hand.","TWN":"來，手給我，握著我的手上來。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"배려 감사합니다. 그럼…","JPN":"お気遣い、ありがとうございます。それでは……","ENG":"Thank you. Then...","TWN":"謝謝，你真貼心，那我就…"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};